@option.validator
def _check_option(self, attribute, value):
    possible_options = [
        self.EMPTY,
        self.YES,
        self.ABSTAIN,
        self.NO,
        self.NO_WITH_VETO,
    ]
    if value not in possible_options:
        raise TypeError(
            f"incorrect value for option: {value}, must be one of: {possible_options}"
        )
